digraph G {
rankdir=LR;
node[shape="box"];

// CPU
subgraph cluster_CPU {
label="Central Processing Unit (CPU)";
node[style=filled];
A[label="Arithmetic Logic Unit (ALU)";shape=circle];
B[label="Control Unit (CU)";shape=circle];
C[label="Central Registers"];
C->B[arrowhead=empty];
C->A[arrowhead=empty];
// Registers
subgraph cluster_Registers {
label="Registers:"
node[style=filled];
D[label="Program Counter (PC)";shape=circle];
E[label="Instruction Register (IR)";shape=circle];
F[label="Memory Address Register (MAR)";shape=circle];
G[label="Memory Buffer Register (MBR)";shape=circle];
H[label="Accumulator (AC)";shape=circle];
I[label="Multiplier-Quotient (MQ) Register";shape=circle];
D->F[arrowhead=empty];
E->B[arrowhead=empty];
F->C[arrowhead=empty];
G->A[arrowhead=empty];
H->A[arrowhead=empty];
I->A[arrowhead=empty];
// I/O
J[label="Input/Output (I/O) Equipment"];
G->J[arrowhead=empty];
}
// Main Memory
K[label="Main Memory (M)"];
F->K[arrowhead=empty];
G->K[arrowhead=empty];
// Data and Control Paths
L[label="Address Bus"];
L->K[arrowhead=empty];
M[label="Data Bus"];
M->K[arrowhead=empty];
N[label="Instruction Fetch Path"];
N->E[arrowhead=empty];
P[label="Control Signal Path"];
P->B[arrowhead=empty];
P->A[arrowhead=empty];
P->D[arrowhead=empty];
P->F[arrowhead=empty];
P->G[arrowhead=empty];
P->J[arrowhead=empty];
}

digraph G {
rankdir=LR;

subgraph cluster_CPU {
label="CPU"; color=lightblue;

node [shape=circle, style=filled]
Control Unit;
Arithmetic Logic Unit (ALU);
Registers;
}

subgraph cluster_Instruction_Memory {
label="Instruction Memory (ROM/RAM)"; color=lightblue;

node [shape=circle, style=filled]
Address Lines;
Data Lines;
Control Lines;
}

subgraph cluster_Data_Memory {
label="Data Memory (RAM)"; color=lightblue;

node [shape=circle, style=filled]
Address Lines;
Data Lines;
Control Lines;
}

CPU -> Instruction_Memory [label = "Instruction Bus"];
CPU -> Data_Memory [label = "Data Bus"];
Instruction_Memory -> CPU [label = "Instruction Code"];
Data_Memory -> CPU [label = "Data"];
}
